import astimport threadingimport timefrom threading import Semaphorefrom .sensor import Sensorfrom .delegates.motion_delegate import MotionDelegatefrom .delegates.scanner_delegate import ScanDelegatefrom .delegates.environment_delegate import EnvironmentDelegatefrom bluepy.btle import Scannerclass Controller(object):    def __init__(self):        self.__scanner = Scanner().withDelegate(ScanDelegate())        # self.__allowed_devices: dict = json.load(open('devices.json'))        self.__connected_devices = []        self.__is_active = True        self.__synchronizer = threading.Event()        self.__threads_counter = 0  # it counts how many threads are ready        self.__semaphore = Semaphore(0)  # semaphore for threads synchronization        self.available_func = {            'help': self.__help,            # 'add_device': self.__add_allowed_device,            'connect': self.__add_connected_device,            # 'allowed_devices': self.__get_allowed_devices,            'connected_devices': self.__get_connected_devices,            'end': self.__end_session        }    def __on_call(self, ch, method, properties, body):        body = ast.literal_eval(body.decode('utf-8'))        if body.get('method') and self.available_func.get(body['method']):            requested_func = body['method']            print(f'Called function: {requested_func}({body["args"]})')            try:                response = self.available_func[requested_func](*body['args'], **body['kwargs'])            except Exception as e:                response = {'error': str(e)}        else:            error_msg = 'Method not found'            response = {'error': error_msg}        ch.basic_publish(            exchange='',            routing_key=properties.reply_to,            body=str(response)        )        ch.basic_ack(delivery_tag=method.delivery_tag)    # RPC methods    def __help(self):        return list(self.available_func.keys())    # def __add_allowed_device(self, device: dict):    #     self.__allowed_devices.update(device)    # def __get_allowed_devices(self):    #     return self.__allowed_devices    def __get_connected_devices(self):        return self.__connected_devices    def __add_connected_device(self, device):        self.__connected_devices.append(device)    def __end_session(self):        self.__is_active = False    # if all threads are ready to recording then return true    def is_ready(self):        if self.__threads_counter == len(self.__connected_devices):            return True        else:            return False    # add a thread in threads_counter    def thread_ready(self):        self.__threads_counter = self.__threads_counter + 1    # return the semaphore    def get_semaphore(self):        return self.__semaphore    # Controller start session    def start_session(self):        print('Session started')        while self.__is_active:            # print('New scan...')            self.__scanner.scan(passive=True)            discovered_devices = list(self.__scanner.getDevices())            for device in discovered_devices:                # Connect only allowed and connectable devices                if device.connectable:                    try:                        # Connection and setup                        thingy = Sensor(                            # nickname=self.__allowed_devices[device.addr.upper()],                            mac=device.addr,                            thread_sync=self.__synchronizer,                            controller=self,                            sensor_delegates=[MotionDelegate],                        )                        # Keep track of connected devices                        self.__add_connected_device(device.addr)                        # Wait for threads synchronization                        thingy.start()                    except Exception as e:                        print(e.args)            # acquire the semaphore --> waiting for all threads            if self.__connected_devices != 0:                self.__semaphore.acquire()                # release threads                self.__synchronizer.set()                # async_result.get()                time.sleep(30)            self.__synchronizer.clear()            while self.__connected_devices:                time.sleep(1)            self.__end_session()        print('Session ended')    def discovery_devices(self):        """Start the discovery"""        self.__scanner = Scanner().withDelegate(ScanDelegate())        discovered_devices = [dev for dev in self.__scanner.scan(passive=True) if dev.connectable]        return discovered_devices    def connect(self, device, dev_name):        try:            # Connection and setup            thingy = Sensor(                nickname=dev_name,                mac=device.addr,                thread_sync=self.__synchronizer,                controller=self,                sensor_delegates=[MotionDelegate],            )            # Keep track of connected devices            self.__add_connected_device(thingy)            thingy.start()            return True        except Exception as e:            print(e.args)            return False    def set_conf(self):        for thingy in self.__connected_devices:            thingy.set_conf()    def set_dev_name(self, dev_name, thingy):        for dev in self.__connected_devices:            if thingy.addr == dev.mac:                dev.configure_device_name(dev_name)                return    def get_battery(self, addr):        return [sensor.battery for sensor in self.__connected_devices if sensor.mac == addr]    def disconnect_device(self, addr):        for cd in self.__connected_devices:            if cd.mac == addr:                self.__connected_devices.remove(cd)                cd.disconnect()                return    def disconnect_all(self):        for cd in self.__connected_devices:            self.__connected_devices.remove(cd)            cd.disconnect()    def start_recording(self):        self.__synchronizer.set()    def stop_recording(self):        self.__synchronizer.clear()